import Axios from 'axios';
import { get } from 'lodash';

import { OneKeyInternalError } from '@onekeyhq/shared/src/errors';
import { ETranslations } from '@onekeyhq/shared/src/locale';
import hexUtils from '@onekeyhq/shared/src/utils/hexUtils';

import sdk from './sdk';
import { submitTransactionFromString } from './transaction';

import type {
  IKaspaGetTransactionResponse,
  IKaspaSubmitTransactionRequest,
  IKaspaUTXOResponse,
} from './types';
import type { AxiosError, AxiosInstance } from 'axios';

// https://api.kaspa.org/docs
export class RestAPIClient {
  private readonly axios: AxiosInstance;

  constructor(url: string) {
    this.axios = Axios.create({
      baseURL: url,
      timeout: 30 * 1000,
    });
  }

  async getBlockdag() {
    try {
      const resp = await this.axios.get<{
        networkName: string;
        blockCount: string;
        headerCount: string;
        virtualDaaScore: string;
      }>('/info/blockdag', {
        headers: {
          'Content-Type': 'application/json',
        },
      });
      return resp.data;
    } catch (_error) {
      return {
        networkName: '',
        blockCount: '0',
        headerCount: '0',
        virtualDaaScore: '0',
      };
    }
  }

  async getNetworkInfo() {
    try {
      const resp = await this.axios.get<{
        networkName: string;
        blockCount: string;
        headerCount: string;
        virtualDaaScore: string;
      }>('/info/network', {
        headers: {
          'Content-Type': 'application/json',
        },
      });
      return resp.data;
    } catch (_error) {
      return {
        networkName: '',
        blockCount: '0',
        headerCount: '0',
        virtualDaaScore: '0',
      };
    }
  }

  async queryBalance(address: string): Promise<bigint> {
    try {
      const resp = await this.axios.get<{ address: string; balance: bigint }>(
        `/addresses/${address}/balance`,
        {
          headers: {
            'Content-Type': 'application/json',
          },
        },
      );
      return resp.data.balance;
    } catch (_error) {
      return 0n;
    }
  }

  async queryUtxos(address: string): Promise<IKaspaUTXOResponse[]> {
    try {
      const resp = await this.axios.get<IKaspaUTXOResponse[]>(
        `/addresses/${address}/utxos`,
        {
          headers: {
            'Content-Type': 'application/json',
          },
        },
      );
      return resp.data;
    } catch (_error) {
      return [];
    }
  }

  async sendRawTransaction(rawTx: string): Promise<string> {
    let transaction: IKaspaSubmitTransactionRequest;
    if (hexUtils.isHexString(rawTx)) {
      transaction = submitTransactionFromString(rawTx);
    } else {
      const api = await sdk.getKaspaApi();
      transaction = {
        transaction: await api.deserializeFromSafeJSON(rawTx),
      };
    }

    return this.axios
      .post<{
        transactionId: string;
        error?: string;
      }>(`/transactions`, transaction, {
        headers: {
          'Content-Type': 'application/json',
        },
      })
      .then((resp) => resp.data.transactionId)
      .catch((error: AxiosError) => {
        const message: string = get(error, 'response.data.error', '');

        if (message.match(/payment of \d+ is dust/)) {
          throw new OneKeyInternalError({
            message,
            key: ETranslations.send_amount_too_small,
          });
        }

        if (message.toLowerCase().indexOf('insufficient balance') !== -1) {
          throw new OneKeyInternalError({
            message,
            key: ETranslations.earn_insufficient_balance,
          });
        }

        throw new OneKeyInternalError(message);
      });
  }

  async getTransaction(
    transactionId: string,
  ): Promise<IKaspaGetTransactionResponse> {
    const resp = await this.axios.get<IKaspaGetTransactionResponse>(
      `/transactions/${transactionId}?inputs=true&outputs=true&resolve_previous_outpoints=light`,
      {
        headers: {
          'Content-Type': 'application/json',
        },
      },
    );
    return resp.data;
  }

  async getTransactions(
    txIds: string[],
  ): Promise<IKaspaGetTransactionResponse[]> {
    const resp = await this.axios.post<IKaspaGetTransactionResponse[]>(
      `/transactions/search?resolve_previous_outpoints=light`,
      {
        transactionIds: [...txIds],
      },
      {
        headers: {
          'Content-Type': 'application/json',
        },
      },
    );
    return resp.data;
  }

  async getTransactionsByAddress(
    address: string,
  ): Promise<IKaspaGetTransactionResponse[]> {
    const resp = await this.axios.get<IKaspaGetTransactionResponse[]>(
      `/addresses/${address}/full-transactions?limit=50&offset=0&resolve_previous_outpoints=light`,
      {
        headers: {
          'Content-Type': 'application/json',
        },
      },
    );
    return resp.data;
  }
}
